1	type Item = { type: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
7	
8	const quotePremium = (items: Item[]): number => {
9	  const basePremium = items.length === 3 ? 60 : items.length * 25;
10	  const withSurcharge = basePremium + (basePremium * FIRST_INSURANCE_SURCHARGE_PERCENT) / 100;
11	  return Math.ceil(withSurcharge) + PROCESSING_FEE;
12	};
13	
14	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
15	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
16	  return { results };
17	};
